var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"소용없습니다.","JPN":"無駄です。","ENG":"Not a chance!","TWN":"沒用的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아쉽네. 방금 건 회심의 한 발이었는데 말이지.","JPN":"残念だな。今のは会心の一発だったのに。","ENG":"Darn, that was my best shot.","TWN":"真可惜，剛才那一箭我很滿意說。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"화살로 절 이길 수는 없습니다.","JPN":"矢では私に勝つことはできません。","ENG":"You cannot beat me with your bow.","TWN":"你用弓箭是打不贏我的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그러니 포기하십시오. 이번 일에 대한 책임은 당주님을 데려온 뒤에 추궁하도록 하죠.","JPN":"ですので諦めてください。\\n今回の件は当主を連れ戻した後に追及することにしましょう。","ENG":"Surrender now. You will be questioned after I bring Lady Nanahara back.","TWN":"你還是放棄吧。等我把堂主帶回來後再向你究責。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"맞아. 내 실력으로는 널 못 이겨.","JPN":"そうだよ。確かに僕の実力じゃ君には勝てない。","ENG":"You’re right. I can’t beat you with my skills.","TWN":"沒錯，我確實打不贏你。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그래도 막을 거야.","JPN":"だけど僕は諦めないよ。","ENG":"But still, I will stop you.","TWN":"但我還是不能放行。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"옛날 나유카 가문 사람들은 큰 뱀을 막겠다는 일념 하나로 화살을 쏴서 하늘의 별을 떨어뜨렸다고 하죠.","JPN":"かつて奈由香家の人々は大蛇を仕留める一心で矢を放ち、\\n天の星を落としたそうです。","ENG":"In the old days, the Nayukas shot down a star only with the fierce determination to stop the Giant Snake.","TWN":"我曾經聽說過，以前南裕夏家族只因為決心要阻止大蛇，而拼命射箭，射到連天上星星都被射下來。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"가문의 맥이 끊긴 말예인 당신에게도 그 자취가 남아 있나 보군요.","JPN":"家系の血筋が途絶えたとはいえ、末裔のあなたにもその名残が残っているようですね。","ENG":"I see you still have that determination in your blood, even after your family’s fall.","TWN":"你身為這個家族的末代子孫，看來也有遺傳到堅持的DNA。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"칭찬 고마워. 그런 얘기를 들으니까 어깨가 무겁네.","JPN":"褒めてくれてありがとう。そんな話を聞くと荷が重くなるよ。","ENG":"Thank you for the big compliment. To hear that, I feel burdened with responsibility.","TWN":"謝謝誇獎。聽到那些話，怎麼覺得肩膀有點重？！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하지만 칭찬을 듣는다고 해서 마음이 바뀌진 않아.","JPN":"それでも僕の気持ちは変わらない。","ENG":"But it won’t change my mind.","TWN":"不過就算你稱讚我，我也不會改變心意的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"너와 싸우고 싶지 않아. 생각을 바꿔 주면 안 될까?","JPN":"考え直してくれないか？　君とは戦いたくないんだ。","ENG":"I don’t want to fight you. Could you please change your mind?","TWN":"我不想和你打起來，不如你退一步吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"어째서 공은 저를 막는 겁니까? 언니를 도망치게 해서 뭘 어쩔 셈인가요?","JPN":"なぜ私を止めるのですか？　姉上を逃がしてどうするおつもりですか？","ENG":"Why do you stop me? Why would you let my sister run away?","TWN":"爲什麼要攔著我？讓姊姊逃掉後，你想要做什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"너야말로, 당주 자릴 차지하는 게 그렇게 중요한 일이야?","JPN":"君こそ、当主の座を得ることがそこまで重要なこと？","ENG":"Why do you care to be the family leader? Why is it so important to you?","TWN":"我倒想問問你，對你而言，當上堂主有那麼重要嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"자매끼리 경쟁하는 게 대체 무슨 의미가 있어?","JPN":"姉妹で競い合うことになんの意味があるの？","ENG":"Why would you compete with your own sister?","TWN":"姊妹之間這樣競爭有什麼意義？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이건 단순한 경쟁이 아닙니다.","JPN":"これは単なる競争ではありません。","ENG":"This is not a simple competition.","TWN":"這不只是單純的競爭。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저희가 어떤 기로 앞에 놓여있는지… 당신은 이해하지 못하겠죠.","JPN":"私たちがどんな岐路に立たされているのか……\\nあなたにはわからないでしょう。","ENG":"You have no idea what’s coming towards us...","TWN":"你不懂……我們要面對什麼樣的抉擇。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"확실히 그 말은 맞을지도 모르지만…….","JPN":"確かにそのとおりかもしれないけど……","ENG":"Maybe you’re right...","TWN":"或許你說的沒錯……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"치나츠는 오로치의 봉인을 다시 막아낼 방법이 있다고 했어.","JPN":"千夏はオロチの封印が解けるのを阻止する方法があると言ったんだ。","ENG":"But Chinatsu told me she knew how to restore Orochi’s seal.","TWN":"但千夏說有辦法可以再次封印住大蛇。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그리고 난, 그 계획을 방해하는 사람들로부터 그 애를 지킬 뿐이야.","JPN":"そして僕は、その計画を邪魔する人々からあの子を守るだけ。","ENG":"I’m only protecting her from the people who are trying to ruin her plan.","TWN":"而我，只是負責保護她，讓她的計畫不受到阻礙。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"지킨다고요?","JPN":"守る？","ENG":"You’re protecting her?","TWN":"保護？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"언니는…… 당신을 속였군요.","JPN":"姉上は……あなたを騙したのですね。","ENG":"My sister... lied to you.","TWN":"姊姊……是騙你的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"えっ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"언니는 사람을 속이는 데는 정말 재주가 없으신 분입니다.","JPN":"姉上は人をだます才能がほとんど無いような方です。","ENG":"She’s a terrible liar.","TWN":"姊姊真的是很不會說謊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만 당신도, 어지간히 남을 의심하는 재주는 없는 모양이군요.","JPN":"ですがあなたも、人を疑う才能があまり無いようですね。","ENG":"And you must be very naive, believing such a terrible liar.","TWN":"不過你也真是好騙。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"치나츠가…… 날 속였다고? 그게 무슨 소리야?","JPN":"千夏が……僕を騙したって？　どういう意味？","ENG":"Chinatsu lied to me? What do you mean?","TWN":"千夏…騙我？那是什麼意思？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"정말로 아무 대가도 없이 오로치를 봉인하는 방법이 있을 거라고 생각한 겁니까?","JPN":"本当に何の代償も払わず\\nオロチを封印できる方法があると思ったのですか？","ENG":"Did you really think that we could seal Orochi without any sacrifice?","TWN":"有不用付任何代價就能將大蛇封印起來的辦法嗎？你認為有這麼好的事嗎?"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나유카 미나토. 당주님을 지키려는 거라면, 공은 실패한 겁니다.","JPN":"奈由香湊。\\n当主を守ることが目的ならば、あなたは失敗したのです。","ENG":"Nayuka Minato. If you wanted to protect her, you failed.","TWN":"南裕夏，如果你是想保護堂主，那你只是在白費功夫。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"지금 당신이 한 짓은 당주님을 죽음으로 내모는 짓이니까요.","JPN":"今あなたがやっていることは、当主を死に追いやる行為ですから。","ENG":"All you did was send her to her own death.","TWN":"因爲你現在所做的，就是將堂主推向死亡。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"치나츠가…… 죽는다고?","JPN":"千夏が……死ぬ？","ENG":"Chinatsu is going to... die?","TWN":"千夏…… 會死？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"설마, 오로치를 봉인하는 대가라는 게…….","JPN":"まさか、オロチを封印する代償は……","ENG":"The sacrifice you said... Does that mean...","TWN":"難道封印大蛇的代價是……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"전 언니를 막으러 갈 겁니다.","JPN":"私は姉上を止めに行きます。","ENG":"I will now go stop my sister.","TWN":"我要去阻止姊姊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"또 다시 저를 막으려고 한다면, 그땐 정말로 벨 수밖에 없습니다.","JPN":"まだ私の邪魔をするのでしたら、その時は本当に斬るしかありません。","ENG":"If you try to stop me again, I really will cut you down.","TWN":"如果你還想攔我，那就休怪刀下無情。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만, 당신이 언니를 돕는 게 아니라 구하고 싶은 거라면……","JPN":"ですが、姉上の手助けをするのではなく、姉上を助けたいと思うのなら……","ENG":"But if you want to protect her...","TWN":"不過，若你是想救姊姊，而不是想幫姊姊………"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"절 따라오는 것을 막지는 않겠습니다.","JPN":"私についてくることを止めはしません。","ENG":"I will let you come with me.","TWN":"那我不會阻你跟著我。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};